const RECOMMENDATIONS = [

  // ═══════════════════════════════════════════════════
  // FLOUR DUST - HSE FL Series
  // ═══════════════════════════════════════════════════

  { id: 1,  group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "Install LEV at the source of dust generation for all flour handling tasks, including bag opening, tipping, dough mixing, moulding, dividing, bagging, and improver handling." },
  { id: 2,  group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "A permanent, fixed dust extraction system is the preferred option; a stand-alone mobile dust collector is acceptable only where fixed installation is not reasonably practicable." },
  { id: 3,  group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "Enclose the process as much as possible - use see-through panels and plastic strip curtains to reduce open areas while maintaining safe access." },
  { id: 4,  group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "Airflow velocity must be sufficient to effectively capture airborne contaminants. Adequacy will depend on hood/enclosure design, opening size, and the specific process and substance." },
  { id: 5,  group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "Keep extraction ductwork as short and direct as possible; avoid long runs of flexible ducting." },
  { id: 6,  group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "Position work areas away from doors, windows, and walkways to prevent draughts from disrupting LEV performance and dispersing airborne dust." },
  { id: 7,  group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "Discharge extracted air to a safe external location, away from doors, windows, and fresh air inlets." },
  { id: 8,  group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "Fit airflow indicators or equivalent devices on all LEV systems to allow workers to confirm the system is operating before commencing work." },
  { id: 9,  group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "Fit filter blockage/failure indicator alarms to all LEV and stand-alone dust collector units." },
  { id: 10, group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "Confirm LEV is switched on and functioning correctly at the start of each work period - check the gauge." },
  { id: 11, group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "For stand-alone dust collectors: the unit must not release dust on start-up and should recirculate clean air; a secondary filter meeting at least dust Type M (medium hazard) classification is required for workplace recirculation." },
  { id: 12, group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "Do not allow the waste bag on stand-alone units to overfill - check gauges regularly and keep sufficient spare filters and bags on site." },
  { id: 13, group: "Flour", cat: "LEV",    sec: "LEV & Engineering Controls",
    text: "Provide a good standard of general (dilution) ventilation throughout the work area to supplement LEV." },

  { id: 14, group: "Flour", cat: "Task",   sec: "Task-specific - Bag Opening, Tipping & Dough Mixing (FL1)",
    text: "Apply LEV with rim extraction at the tipping/mixing point; put a solid lid on the mixer where practicable." },
  { id: 15, group: "Flour", cat: "Task",   sec: "Task-specific - Bag Opening, Tipping & Dough Mixing (FL1)",
    text: "Tip flour gently - never dump. Add ingredients gently, trickle water down the inside of the bowl, and start the mixer on slow speed." },
  { id: 16, group: "Flour", cat: "Task",   sec: "Task-specific - Bag Opening, Tipping & Dough Mixing (FL1)",
    text: "When crushing empty bags, roll them up with the open end positioned within the extraction zone to capture released dust." },
  { id: 17, group: "Flour", cat: "Task",   sec: "Task-specific - Bag Opening, Tipping & Dough Mixing (FL1)",
    text: "Consider providing mechanical or pneumatic bag/sack handling assistance to reduce manual handling and dust generation." },

  { id: 18, group: "Flour", cat: "Task",   sec: "Task-specific - Weighing & Handling Flour Improvers (FL2)",
    text: "Use LEV cabinet extraction when weighing flour improvers." },
  { id: 19, group: "Flour", cat: "Task",   sec: "Task-specific - Weighing & Handling Flour Improvers (FL2)",
    text: "Substitute high-dust improvers with low-dust alternatives wherever possible, e.g. dust-suppressed products, low-dust granules, or paste formulations." },
  { id: 20, group: "Flour", cat: "Task",   sec: "Task-specific - Weighing & Handling Flour Improvers (FL2)",
    text: "Eliminate weighing entirely where practicable by using single-dose packets." },
  { id: 21, group: "Flour", cat: "Task",   sec: "Task-specific - Weighing & Handling Flour Improvers (FL2)",
    text: "Open improver containers with care to minimise dust release; keep used scoops and utensils inside the extraction cabinet until cleaned." },

  { id: 22, group: "Flour", cat: "Task",   sec: "Task-specific - Dough Moulding & Dividing (FL3)",
    text: "Apply LEV with extraction slots at the rear of the work table; keep extraction slots free from obstructions at all times." },
  { id: 23, group: "Flour", cat: "Task",   sec: "Task-specific - Dough Moulding & Dividing (FL3)",
    text: "Eliminate dusting with flour wherever possible - use non-stick table surfaces or food-grade oil as a lubricant." },
  { id: 24, group: "Flour", cat: "Task",   sec: "Task-specific - Dough Moulding & Dividing (FL3)",
    text: "Where dusting cannot be avoided, workers should cast flour gently towards the extraction slots rather than across the open workspace." },
  { id: 25, group: "Flour", cat: "Task",   sec: "Task-specific - Dough Moulding & Dividing (FL3)",
    text: "Provide easy access to remove dust build-up behind extraction slots." },

  { id: 26, group: "Flour", cat: "Task",   sec: "Task-specific - Flour Bagging (FL5)",
    text: "Apply LEV enclosing the bagging point; use a filling nozzle that directs displaced air directly into the extraction system." },
  { id: 27, group: "Flour", cat: "Task",   sec: "Task-specific - Flour Bagging (FL5)",
    text: "Ensure the filling nozzle design does not spill flour when a bag is removed." },
  { id: 28, group: "Flour", cat: "Task",   sec: "Task-specific - Flour Bagging (FL5)",
    text: "Provide an extracted hopper at floor level to capture flour spills." },

  { id: 29, group: "Flour", cat: "Task",   sec: "Task-specific - Bulk Improver Addition in Flour Milling (FL6)",
    text: "Automate this task wherever technically feasible." },
  { id: 30, group: "Flour", cat: "Task",   sec: "Task-specific - Bulk Improver Addition in Flour Milling (FL6)",
    text: "Apply LEV enclosing the hopper feed tray." },
  { id: 31, group: "Flour", cat: "Task",   sec: "Task-specific - Bulk Improver Addition in Flour Milling (FL6)",
    text: "Use low-dust improver formulations (dust-suppressed products or low-dust granules); avoid weighing by using single-dose packets or whole bags wherever possible." },
  { id: 32, group: "Flour", cat: "Task",   sec: "Task-specific - Bulk Improver Addition in Flour Milling (FL6)",
    text: "Train workers to tip additives gently into the hopper - never dump. Ensure empty bags are rolled up with the open end within the extraction zone." },

  { id: 33, group: "Flour", cat: "RPE",    sec: "Respiratory Protective Equipment",
    text: "RPE with a UK Standard Assigned Protection Factor (APF) of at least 20 is required for the manual addition of bulk improvers to flour in milling operations (FL6) - this is in addition to engineering controls, not instead of them." },
  { id: 34, group: "Flour", cat: "RPE",    sec: "Respiratory Protective Equipment",
    text: "Provide RPE for all maintenance and cleaning activities associated with flour handling equipment and LEV systems." },
  { id: 35, group: "Flour", cat: "RPE",    sec: "Respiratory Protective Equipment",
    text: "Where tight-fitting RPE is used: fit testing is mandatory; workers must be clean-shaven; train workers in correct donning, doffing, and pre-use checks." },
  { id: 36, group: "Flour", cat: "RPE",    sec: "Respiratory Protective Equipment",
    text: "Disposable RPE must be discarded at the end of each shift, or sooner if it becomes blocked." },
  { id: 37, group: "Flour", cat: "RPE",    sec: "Respiratory Protective Equipment",
    text: "Replace reusable respirator filters in accordance with manufacturer guidance and whenever filters are past shelf-life, visibly damaged or contaminated, or breathing resistance increases." },
  { id: 38, group: "Flour", cat: "RPE",    sec: "Respiratory Protective Equipment",
    text: "Carry out RPE examination and testing at least monthly (or before each use if infrequent - intervals must not exceed three months)." },
  { id: 39, group: "Flour", cat: "RPE",    sec: "Respiratory Protective Equipment",
    text: "Where RPE is required for periods exceeding one hour, provide powered air-purifying respirators (PAPR) or constant-flow airline breathing apparatus." },
  { id: 40, group: "Flour", cat: "RPE",    sec: "Respiratory Protective Equipment",
    text: "Keep all RPE clean and store in a clean, designated location when not in use." },

  { id: 41, group: "Flour", cat: "PPE",    sec: "PPE & Skin Protection",
    text: "Provide coveralls that do not retain dust; arrange laundering through a contract laundry service - workers must not launder work clothing at home." },
  { id: 42, group: "Flour", cat: "PPE",    sec: "PPE & Skin Protection",
    text: "Provide warm water, mild skin cleansers, and soft paper or fabric towels at all wash stations - avoid abrasive cleansers." },
  { id: 43, group: "Flour", cat: "PPE",    sec: "PPE & Skin Protection",
    text: "Provide pre-work emollient skin creams to facilitate post-work skin cleansing." },
  { id: 44, group: "Flour", cat: "PPE",    sec: "PPE & Skin Protection",
    text: "Provide after-work emollient creams to replenish skin lipids following handwashing." },
  { id: 45, group: "Flour", cat: "PPE",    sec: "PPE & Skin Protection",
    text: "Note: barrier creams do not constitute a complete physical barrier and must not be used as a substitute for other protective measures." },

  { id: 46, group: "Flour", cat: "Maint",  sec: "Maintenance, Examination & Testing",
    text: "LEV systems are subject to a statutory Thorough Examination and Test (TExT) under COSHH Regulation 9; this must be carried out by a competent person at intervals not exceeding 14 months." },
  { id: 47, group: "Flour", cat: "Maint",  sec: "Maintenance, Examination & Testing",
    text: "Carry out a visual check of all control equipment for signs of damage or deterioration before commencing work each day." },
  { id: 48, group: "Flour", cat: "Maint",  sec: "Maintenance, Examination & Testing",
    text: "Maintain a LEV user manual or log book recording performance specifications, inspection frequency, maintenance schedules, and parts replacement history." },
  { id: 49, group: "Flour", cat: "Maint",  sec: "Maintenance, Examination & Testing",
    text: "Retain records of all LEV examinations and tests for a minimum of 5 years." },
  { id: 50, group: "Flour", cat: "Maint",  sec: "Maintenance, Examination & Testing",
    text: "Act on all remedial actions identified by TExT reports without undue delay." },
  { id: 51, group: "Flour", cat: "Maint",  sec: "Maintenance, Examination & Testing",
    text: "Effectiveness of controls should be verified using qualitative dust lamp (Tyndall beam) checks or quantitative air sampling for higher-risk scenarios - refer to HSG258." },

  { id: 52, group: "Flour", cat: "Clean",  sec: "Cleaning & Housekeeping",
    text: "Clean work equipment and the immediate work area at the end of each shift (daily minimum)." },
  { id: 53, group: "Flour", cat: "Clean",  sec: "Cleaning & Housekeeping",
    text: "Clean the wider workroom, including overhead beams, heating pipework, and light fittings, at least once per week." },
  { id: 54, group: "Flour", cat: "Clean",  sec: "Cleaning & Housekeeping",
    text: "Remove dry flour dust by vacuum cleaning or wet methods only - vacuum equipment must meet at least dust Class M (medium hazard) classification." },
  { id: 55, group: "Flour", cat: "Clean",  sec: "Cleaning & Housekeeping",
    text: "Deal with flour spills immediately; shovel large spills carefully into a waste bag or spill hopper." },
  { id: 56, group: "Flour", cat: "Clean",  sec: "Cleaning & Housekeeping",
    text: "Never use brushes or compressed air to remove dust from clothing, skin, or equipment surfaces - these methods disperse dust into the breathing zone." },

  { id: 57, group: "Flour", cat: "Health", sec: "Health Surveillance",
    text: "Implement a health surveillance programme for occupational asthma where there is a reasonable likelihood of asthma developing (refer to HSE G402)." },
  { id: 58, group: "Flour", cat: "Health", sec: "Health Surveillance",
    text: "Implement a health surveillance programme for occupational dermatitis where there is a reasonable likelihood of dermatitis developing (refer to HSE G403)." },
  { id: 59, group: "Flour", cat: "Health", sec: "Health Surveillance",
    text: "Inform workers of the early signs and symptoms of occupational asthma and contact dermatitis and advise them to report any symptoms to their line manager promptly." },

  { id: 60, group: "Flour", cat: "Train",  sec: "Training & Supervision",
    text: "Permit access to flour handling areas to authorised and appropriately trained personnel only." },
  { id: 61, group: "Flour", cat: "Train",  sec: "Training & Supervision",
    text: "Provide documented training covering: health hazards of flour dust and enzyme improvers; correct use and checking of LEV; correct use, maintenance, and storage of RPE and PPE; and actions in the event of control failure." },
  { id: 62, group: "Flour", cat: "Train",  sec: "Training & Supervision",
    text: "Maintain training records as evidence that training has been delivered and understood." },
  { id: 63, group: "Flour", cat: "Train",  sec: "Training & Supervision",
    text: "Review and update training whenever work processes, substances, or LEV systems change." },
  { id: 64, group: "Flour", cat: "Train",  sec: "Training & Supervision",
    text: "Include managers and supervisors in all relevant health and safety training." },
  { id: 65, group: "Flour", cat: "Train",  sec: "Training & Supervision",
    text: "Provide active supervision to ensure safe work procedures are consistently followed." },

  { id: 66, group: "Flour", cat: "Exp",    sec: "Occupational Exposure Benchmark",
    text: "When all COSHH controls are correctly implemented, flour dust concentrations of less than 2 mg/m\u00b3 (8-hour TWA) should be achievable at all assessed tasks." },
  { id: 67, group: "Flour", cat: "Exp",    sec: "Occupational Exposure Benchmark",
    text: "Where monitoring results exceed 2 mg/m\u00b3 TWA, controls should be reviewed and remedial actions implemented before re-sampling." },
  { id: 68, group: "Flour", cat: "Exp",    sec: "Occupational Exposure Benchmark",
    text: "The Workplace Exposure Limit (WEL) for flour dust is 10 mg/m\u00b3 (8-hr TWA); the HSE recommends exposure be reduced as far below the WEL as reasonably practicable - 2 mg/m\u00b3 represents good control practice performance." },

  // ═══════════════════════════════════════════════════
  // AGRICULTURE - HSE AG Series
  // ═══════════════════════════════════════════════════

  { id: 69,  group: "Agriculture", cat: "Cab",    sec: "Harvesting Grain & Seed Crops (AG1)",
    text: "Use a combine harvester with an enclosed, ventilated cab fitted with filtered air intakes; confirm clean air is turned on and self-test every time the harvester is started." },
  { id: 70,  group: "Agriculture", cat: "Cab",    sec: "Harvesting Grain & Seed Crops (AG1)",
    text: "Close cab doors and windows at all times during harvesting to keep dust out." },
  { id: 71,  group: "Agriculture", cat: "Cab",    sec: "Harvesting Grain & Seed Crops (AG1)",
    text: "Where reasonably practicable, use a tractor with an enclosed, ventilated cab fitted with filtered air intakes for trailers collecting grain; try to stay upwind of dust clouds." },
  { id: 72,  group: "Agriculture", cat: "RPE",    sec: "Harvesting Grain & Seed Crops (AG1)",
    text: "Provide RPE with a UK Standard APF of at least 10 for maintenance, cleaning inside machinery, or where dust clouds are unavoidable." },
  { id: 73,  group: "Agriculture", cat: "Maint",  sec: "Harvesting Grain & Seed Crops (AG1)",
    text: "Carry out daily checks of vehicle cab filtration: inspect door and window seals, check pre-filters, verify filter seating condition, and change HEPA inlet air filters as advised by the manufacturer." },
  { id: 74,  group: "Agriculture", cat: "Clean",  sec: "Harvesting Grain & Seed Crops (AG1)",
    text: "Clean the cab at least once a week during harvest using vacuum equipment meeting at least dust Class M classification or wet cleaning methods - never use brushes or compressed air." },
  { id: 75,  group: "Agriculture", cat: "Maint",  sec: "Harvesting Grain & Seed Crops (AG1)",
    text: "Keep records of all equipment examinations for at least 5 years; get a competent engineer to examine vehicle air filtration at suitable intervals." },

  { id: 76,  group: "Agriculture", cat: "Task",   sec: "Grain & Seed Transfer, Small Scale (AG2)",
    text: "Segregate the tipping point from the grain store; where possible turn on the equipment and leave the area before dust is generated." },
  { id: 77,  group: "Agriculture", cat: "Task",   sec: "Grain & Seed Transfer, Small Scale (AG2)",
    text: "Minimise dust escapes by enclosing the tipping point with plastic strip curtains and discharging into covered storage bins through a sock." },
  { id: 78,  group: "Agriculture", cat: "LEV",    sec: "Grain & Seed Transfer, Small Scale (AG2)",
    text: "Apply LEV at the source of exposure; use enclosed or extracted elevators and conveyors; airflow must be sufficient to control airborne contaminants effectively." },
  { id: 79,  group: "Agriculture", cat: "LEV",    sec: "Grain & Seed Transfer, Small Scale (AG2)",
    text: "Provide an airflow indicator on LEV systems and mark the acceptable range of readings on the gauge; keep extraction ducts short and simple." },
  { id: 80,  group: "Agriculture", cat: "Maint",  sec: "Grain & Seed Transfer, Small Scale (AG2)",
    text: "LEV systems require a statutory TExT by a competent person at intervals not exceeding 14 months; retain records of all examinations for at least 5 years." },
  { id: 81,  group: "Agriculture", cat: "RPE",    sec: "Grain & Seed Transfer, Small Scale (AG2)",
    text: "Provide RPE with a UK Standard APF of at least 10 for maintenance, cleaning, or where dust clouds cannot be avoided; examine and test non-disposable RPE at least monthly." },
  { id: 82,  group: "Agriculture", cat: "Clean",  sec: "Grain & Seed Transfer, Small Scale (AG2)",
    text: "Clean work equipment and the work area daily; clean other equipment at least once a week; use vacuum equipment meeting at least dust Class M classification." },

  { id: 83,  group: "Agriculture", cat: "Task",   sec: "Weighing, Milling & Mixing Animal Feeds (AG3)",
    text: "Avoid weighing out additives where possible - buy in one-shot packages; consider suppressing dust by using molasses or oil in the feed formula." },
  { id: 84,  group: "Agriculture", cat: "LEV",    sec: "Weighing, Milling & Mixing Animal Feeds (AG3)",
    text: "Fit the hopper, mixer and bagging-off point with LEV; fit lids where dust can escape and enclose chutes; auger mixed feed to storage bins." },
  { id: 85,  group: "Agriculture", cat: "LEV",    sec: "Weighing, Milling & Mixing Animal Feeds (AG3)",
    text: "When operating inside a shed provide general ventilation with greater than five air changes per hour with a through draught; discharge extracted air away from doors, windows and air inlets." },
  { id: 86,  group: "Agriculture", cat: "Task",   sec: "Weighing, Milling & Mixing Animal Feeds (AG3)",
    text: "Place machinery controls outside the working area and provide an emergency stop near the machine; in larger plants, provide a separate control room." },
  { id: 87,  group: "Agriculture", cat: "Cab",    sec: "Weighing, Milling & Mixing Animal Feeds (AG3)",
    text: "Where a vehicle is used, use one with an enclosed, ventilated cab fitted with filtered air intakes; check clean air is working and self-test every time the vehicle is started; keep doors and windows closed." },
  { id: 88,  group: "Agriculture", cat: "RPE",    sec: "Weighing, Milling & Mixing Animal Feeds (AG3)",
    text: "Provide RPE with a UK Standard APF of at least 10 for maintenance, cleaning, or unavoidable dust exposure; if RPE is required for more than 1 hour, use powered respirators." },

  { id: 89,  group: "Agriculture", cat: "Task",   sec: "Feeding Livestock Housed Indoors (AG4)",
    text: "Automate feeding where possible using enclosed elevators, conveyors or an auger; use pelletised or slurry feeds which produce less dust." },
  { id: 90,  group: "Agriculture", cat: "Task",   sec: "Feeding Livestock Housed Indoors (AG4)",
    text: "Where manual feeding cannot be avoided, pour feed gently - never throw or dump it." },
  { id: 91,  group: "Agriculture", cat: "RPE",    sec: "Feeding Livestock Housed Indoors (AG4)",
    text: "Provide RPE with a UK Standard APF of at least 10 for all dusty operations; workers wearing tight-fitting RPE must be clean-shaven and trained in correct fit, use and maintenance." },
  { id: 92,  group: "Agriculture", cat: "RPE",    sec: "Feeding Livestock Housed Indoors (AG4)",
    text: "Examine and test non-disposable RPE at least once per month; keep RPE clean and store in a clean place; discard disposable RPE at the end of each shift or sooner if blocked." },
  { id: 93,  group: "Agriculture", cat: "Health", sec: "Feeding Livestock Housed Indoors (AG4)",
    text: "Provide health surveillance for occupational asthma and dermatitis where there is a reasonable likelihood these may occur (refer to HSE G402 and G403)." },

  { id: 94,  group: "Agriculture", cat: "Task",   sec: "Grain & Seed Cleaning, Fixed & Mobile (AG5)",
    text: "If possible, locate mobile plant outside; indoors, provide general ventilation with greater than five clean air changes per hour and a through draught." },
  { id: 95,  group: "Agriculture", cat: "LEV",    sec: "Grain & Seed Cleaning, Fixed & Mobile (AG5)",
    text: "Fit the machine hopper, cleaning head and bagging-off point with LEV; roll up empty bags with the open end in a dust extraction zone or do this outside." },
  { id: 96,  group: "Agriculture", cat: "Task",   sec: "Grain & Seed Cleaning, Fixed & Mobile (AG5)",
    text: "If not bagging, discharge cleaned seed into a covered storage container through a sock; discharge extracted air to a safe place away from doors, windows and air inlets." },
  { id: 97,  group: "Agriculture", cat: "Task",   sec: "Grain & Seed Cleaning, Fixed & Mobile (AG5)",
    text: "Move seed gently - never throw or dump it; for seed dressing products, follow all handling instructions on the product label." },
  { id: 98,  group: "Agriculture", cat: "Maint",  sec: "Grain & Seed Cleaning, Fixed & Mobile (AG5)",
    text: "LEV systems require a statutory TExT at intervals not exceeding 14 months; permit-to-work procedures may be required for maintenance activities." },

  { id: 99,  group: "Agriculture", cat: "Task",   sec: "Opening Hay, Haylage & Silage Bales (AG6)",
    text: "Handle hay, haylage and silage gently at all times to avoid stirring up dust and spores." },
  { id: 100, group: "Agriculture", cat: "RPE",    sec: "Opening Hay, Haylage & Silage Bales (AG6)",
    text: "Provide RPE with a UK Standard APF of at least 10 for all dusty bale-opening operations; examine and test non-disposable RPE at least monthly." },
  { id: 101, group: "Agriculture", cat: "PPE",    sec: "Opening Hay, Haylage & Silage Bales (AG6)",
    text: "Provide protective coveralls; ask your supplier to advise on suitable PPE for bale handling." },
  { id: 102, group: "Agriculture", cat: "Health", sec: "Opening Hay, Haylage & Silage Bales (AG6)",
    text: "Provide health surveillance for occupational asthma where there is a reasonable likelihood it may occur (refer to HSE G402)." },

  { id: 103, group: "Agriculture", cat: "Cab",    sec: "Composting (AG7)",
    text: "Where reasonably practicable use a vehicle with an enclosed, ventilated cab fitted with filtered air intakes for moving compost; keep doors and windows closed; if not possible, wear RPE." },
  { id: 104, group: "Agriculture", cat: "LEV",    sec: "Composting (AG7)",
    text: "Apply LEV at the source of exposure for conveyors, screens and transfer points; use enclosed or extracted elevators, conveyors and screens; discharge extracted air away from doors, windows and air inlets." },
  { id: 105, group: "Agriculture", cat: "LEV",    sec: "Composting (AG7)",
    text: "Provide an airflow indicator on all LEV and mark the acceptable operating range on the gauge; keep ducts short and simple." },
  { id: 106, group: "Agriculture", cat: "Maint",  sec: "Composting (AG7)",
    text: "Carry out daily checks of vehicle cab filtration including door and window seals, pre-filters, filter seating and HEPA filters; get a competent engineer to examine air filtration at suitable intervals." },
  { id: 107, group: "Agriculture", cat: "RPE",    sec: "Composting (AG7)",
    text: "Provide RPE with a UK Standard APF of at least 10 for maintenance, cleaning, or where dust/bioaerosol clouds are unavoidable; use powered respirators if RPE is required for more than 1 hour." },
  { id: 108, group: "Agriculture", cat: "Maint",  sec: "Composting (AG7)",
    text: "LEV systems require a statutory TExT at intervals not exceeding 14 months; retain all examination records for at least 5 years." },

  { id: 109, group: "Agriculture", cat: "Cab",    sec: "Straw Chopping & Blowing (AG8)",
    text: "Use a vehicle with an enclosed, ventilated cab fitted with filtered air intakes; try to keep upwind of dust clouds; keep doors and windows closed throughout the operation." },
  { id: 110, group: "Agriculture", cat: "Task",   sec: "Straw Chopping & Blowing (AG8)",
    text: "Provide general ventilation with greater than five air changes per hour using powered wall- or window-mounted fans with a through draught." },
  { id: 111, group: "Agriculture", cat: "Task",   sec: "Straw Chopping & Blowing (AG8)",
    text: "Allow a minimum of 10 minutes for dust to settle before entering the building after straw chopping or blowing - or wear RPE on entry." },
  { id: 112, group: "Agriculture", cat: "RPE",    sec: "Straw Chopping & Blowing (AG8)",
    text: "Wear RPE when using hand-push straw choppers; provide RPE with a UK Standard APF of at least 10 for maintenance, cleaning, or unavoidable dust exposure." },
  { id: 113, group: "Agriculture", cat: "Maint",  sec: "Straw Chopping & Blowing (AG8)",
    text: "Carry out daily checks of vehicle cab filtration: door and window seals, pre-filters, filter seating and HEPA inlet air filters; clean the cab at least once a week using Class M vacuum equipment or wet methods." },

  { id: 114, group: "Agriculture", cat: "Clean",  sec: "Cleaning Grain & Feed Stores, Sheds & Silos (AG9)",
    text: "Remove as much dust as possible by mechanical means and vacuum cleaning before applying any chemical cleaning products; avoid dry brushing and compressed air wherever possible." },
  { id: 115, group: "Agriculture", cat: "Task",   sec: "Cleaning Grain & Feed Stores, Sheds & Silos (AG9)",
    text: "Check safety data sheets for all cleaning chemicals; substitute with safer products where possible; avoid products labelled 'may cause sensitisation by inhalation or skin contact'." },
  { id: 116, group: "Agriculture", cat: "RPE",    sec: "Cleaning Grain & Feed Stores, Sheds & Silos (AG9)",
    text: "Provide RPE with a UK Standard APF of at least 20; depending on products used, a combination filter for dust and vapour may be required; workers must put on RPE before entering the area." },
  { id: 117, group: "Agriculture", cat: "RPE",    sec: "Cleaning Grain & Feed Stores, Sheds & Silos (AG9)",
    text: "Provide air-fed breathing apparatus for work in confined spaces such as closed silos or conveyor boots, or where compressed air is used for cleaning." },
  { id: 118, group: "Agriculture", cat: "PPE",    sec: "Cleaning Grain & Feed Stores, Sheds & Silos (AG9)",
    text: "Provide PPE to minimise skin contact with chemicals; nitrile gloves are typically acceptable - check product labels; consider safe access arrangements for working at height." },
  { id: 119, group: "Agriculture", cat: "Clean",  sec: "Cleaning Grain & Feed Stores, Sheds & Silos (AG9)",
    text: "Deal with chemical spills immediately using suitable protective gloves; clean work equipment at least once a week." },

  { id: 120, group: "Agriculture", cat: "Task",   sec: "On-Farm Cleaning & Grading of Bulbs, Roots & Tubers (AG10)",
    text: "Segregate the tipping point and cleaning machine from power controls and other work areas; minimise time workers spend next to running machines." },
  { id: 121, group: "Agriculture", cat: "LEV",    sec: "On-Farm Cleaning & Grading of Bulbs, Roots & Tubers (AG10)",
    text: "Apply LEV at the source of exposure for cleaning machines, elevators, conveyors, grading machines and bagging-off points; airflow must be sufficient to effectively capture airborne contaminants." },
  { id: 122, group: "Agriculture", cat: "LEV",    sec: "On-Farm Cleaning & Grading of Bulbs, Roots & Tubers (AG10)",
    text: "Provide general ventilation with greater than five air changes per hour using powered wall- or window-mounted fans with a through draught; mark the acceptable range of readings on LEV gauges." },
  { id: 123, group: "Agriculture", cat: "Exp",    sec: "On-Farm Cleaning & Grading of Bulbs, Roots & Tubers (AG10)",
    text: "Keep exposures to respirable crystalline silica (RCS) below 0.1 mg/m\u00b3 (8-hour TWA) - dry soil associated with bulbs, roots and tubers may contain silica." },
  { id: 124, group: "Agriculture", cat: "PPE",    sec: "On-Farm Cleaning & Grading of Bulbs, Roots & Tubers (AG10)",
    text: "Provide overalls that do not retain dust (smooth synthetic fabrics, not cotton or knitted); provide single-use nitrile gloves - handling bulbs, roots and tubers without gloves can cause dermatitis." },
  { id: 125, group: "Agriculture", cat: "RPE",    sec: "On-Farm Cleaning & Grading of Bulbs, Roots & Tubers (AG10)",
    text: "Provide RPE with a UK Standard APF of at least 10 for maintenance, cleaning, or unavoidable dust exposure; LEV systems require a statutory TExT at intervals not exceeding 14 months." },
  { id: 126, group: "Agriculture", cat: "Health", sec: "On-Farm Cleaning & Grading of Bulbs, Roots & Tubers (AG10)",
    text: "Provide health surveillance for occupational asthma and dermatitis where there is a reasonable likelihood these may occur (refer to HSE G402 and G403)." },

  // ═══════════════════════════════════════════════════
  // METALWORKING FLUIDS - HSE MW Series
  // ═══════════════════════════════════════════════════

  // MW1 - CNC Machining
  { id: 127, group: "Metalworking Fluids", cat: "LEV",   sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Enclose CNC machines as much as possible, e.g. retrofitting roof panels, to minimise escape of MWF mist." },
  { id: 128, group: "Metalworking Fluids", cat: "LEV",   sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Provide LEV to the CNC enclosure, either as a standalone unit or a centralised system. Design considerations must include volume flow rate, location of extraction points, enclosure dimensions and the level of mist generated." },
  { id: 129, group: "Metalworking Fluids", cat: "LEV",   sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Discharge extracted air to a safe place outside the building, away from doors, windows and air inlets. If recirculated back into the workshop, ensure a suitable high efficiency air cleaning device is in place." },
  { id: 130, group: "Metalworking Fluids", cat: "LEV",   sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Provide an easy way of checking the LEV is working, e.g. airflow indicator or equivalent; check for swarf accumulating around the extraction point before starting work." },
  { id: 131, group: "Metalworking Fluids", cat: "Task",  sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Apply MWF at the lowest possible pressure and flow volume consistent with adequate lubrication, cooling and swarf removal; apply at the point of tool-workpiece contact to minimise mist generation from other rotating parts." },
  { id: 132, group: "Metalworking Fluids", cat: "Task",  sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Stop MWF delivery when not machining, but maintain fluid circulation to prevent stagnation (see MW5 Managing fluid quality)." },
  { id: 133, group: "Metalworking Fluids", cat: "Task",  sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Observe a time delay between the machine stopping and opening the enclosure doors to ensure no mist is present in the operator's breathing zone (within 20-30 cm of nose and mouth). Implement via machine programme or timer." },
  { id: 134, group: "Metalworking Fluids", cat: "Task",  sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Avoid using compressed air guns to clean components - use alternatives such as vacuum guns, absorbent materials, low pressure coolant guns, spindle-mounted fans or automatic compressed air hoses operated with enclosure doors shut." },
  { id: 135, group: "Metalworking Fluids", cat: "Task",  sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Where compressed air guns cannot be avoided: reduce exit pressure to as low as practicable (30 psi/2.1 bar is effective); use longer lances (e.g. 30 cm); blow down components inside the machine with LEV operating. Never use compressed air for cleaning skin or clothing." },
  { id: 136, group: "Metalworking Fluids", cat: "Task",  sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Use suitable swarf vacuums to remove wet swarf/chips from machine surfaces. Finished components can be cleaned in industrial washing/degreasing machines." },
  { id: 137, group: "Metalworking Fluids", cat: "Maint", sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Carry out weekly checks for signs of damage to flexible ducts and filter housings; repair faulty extraction systems promptly." },
  { id: 138, group: "Metalworking Fluids", cat: "Maint", sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "LEV systems require a statutory TExT by a competent person at intervals not exceeding 14 months; retain records of all examinations and tests for at least 5 years; carry out all remedial actions arising from the TExT." },
  { id: 139, group: "Metalworking Fluids", cat: "Maint", sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Maintain an LEV system logbook containing schedules and records of regular checking, maintenance and repair. Where no logbook, user manual or commissioning report exists, seek help from a competent person such as an occupational hygienist specialising in LEV." },
  { id: 140, group: "Metalworking Fluids", cat: "Health", sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Provide health surveillance where workers regularly inhale MWF mists and there is a reasonable likelihood that asthma may develop (refer to HSE G402); provide health surveillance for dermatitis where there is a reasonable likelihood it may occur (refer to HSE G403)." },
  { id: 141, group: "Metalworking Fluids", cat: "Train", sec: "CNC Machining - LEV & Engineering Controls (MW1)",
    text: "Train workers on: health hazards of MWF; how the LEV system works and how to check it; when and how to use alternatives to compressed air guns; how to use compressed air guns to minimise exposure; what to do if something goes wrong." },

  // MW2 - Control of skin risks during machining
  { id: 142, group: "Metalworking Fluids", cat: "Task",  sec: "Skin Risk Control During Machining (MW2)",
    text: "Select MWF carefully - consult your fluid supplier as there may be a fluid with less hazardous components; consider your selection as part of managing skin risks." },
  { id: 143, group: "Metalworking Fluids", cat: "Task",  sec: "Skin Risk Control During Machining (MW2)",
    text: "Minimise tramp oil leaks into the sump; remove tramp oil using mechanical skimmers, mobile oil coalescers or vacuum systems; remove fines using centrifuges, filtration systems or magnetic separators." },
  { id: 144, group: "Metalworking Fluids", cat: "Task",  sec: "Skin Risk Control During Machining (MW2)",
    text: "Mix fresh water-mix fluids to the supplier's recommended concentration. Top up only with fluid below recommended concentration as fluids evaporate and become more concentrated in use." },
  { id: 145, group: "Metalworking Fluids", cat: "Task",  sec: "Skin Risk Control During Machining (MW2)",
    text: "Do not add biocide until all good practice measures to maintain the fluid have been followed; add the right amount directly to the sump. Higher than recommended fluid or biocide concentration increases the risk of skin disease." },
  { id: 146, group: "Metalworking Fluids", cat: "Task",  sec: "Skin Risk Control During Machining (MW2)",
    text: "Prevent skin contact with MWF wherever possible; use automatic mixing devices instead of manual mixing; enclose machines as much as possible; reduce splash risks and provide properly designed splash-guards where not fully enclosed." },
  { id: 147, group: "Metalworking Fluids", cat: "Task",  sec: "Skin Risk Control During Machining (MW2)",
    text: "Use suitable tools (brushes, magnetic wands, swarf hooks) to remove swarf/chips from machine surfaces. Never remove swarf and fines from the sump by hand - use brushes, shovels and cut-resistant protective gloves." },
  { id: 148, group: "Metalworking Fluids", cat: "PPE",   sec: "Skin Risk Control During Machining (MW2)",
    text: "Provide single-use nitrile gloves suitable for controlling skin exposure to MWFs, but only where these do not add to other machinery risks such as entanglement; provide thicker gloves for cleaning and maintenance tasks (machinery switched off only)." },
  { id: 149, group: "Metalworking Fluids", cat: "PPE",   sec: "Skin Risk Control During Machining (MW2)",
    text: "Provide eye protection (goggles or safety glasses); provide overalls ensuring forearms are covered; ensure contaminated overalls are laundered before re-use using a contract laundry or suitable equivalent." },
  { id: 150, group: "Metalworking Fluids", cat: "PPE",   sec: "Skin Risk Control During Machining (MW2)",
    text: "Provide warm water, mild skin cleansers and soft paper or fabric towels at wash stations; provide pre-work creams and after-work creams to restore skin moisture. Note: barrier creams are not liquid gloves and do not provide a full barrier." },
  { id: 151, group: "Metalworking Fluids", cat: "Clean", sec: "Skin Risk Control During Machining (MW2)",
    text: "Keep surfaces clean to minimise MWF contact; deal with spills immediately using a vacuum system and absorbent materials; dispose of spilt MWF safely - do not return it to the machine as this contaminates the system." },
  { id: 152, group: "Metalworking Fluids", cat: "Health", sec: "Skin Risk Control During Machining (MW2)",
    text: "Provide health surveillance for dermatitis where there is a reasonable likelihood it may occur (refer to HSE G403); tell workers to check their skin regularly for dryness or soreness and report any symptoms." },

  // MW3 - Sump cleaning: water-mix fluids
  { id: 153, group: "Metalworking Fluids", cat: "Task",  sec: "Sump Cleaning - Water-mix Fluids (MW3)",
    text: "Decide on sump cleaning frequency based on visual inspection and monitoring results in consultation with the fluid supplier; provide equipment to remove and replace sump fluids with minimum spillage, e.g. wet vacuum." },
  { id: 154, group: "Metalworking Fluids", cat: "Task",  sec: "Sump Cleaning - Water-mix Fluids (MW3)",
    text: "Avoid the use of high pressure water hoses for sump cleaning where practicable; keep absorbent material to hand in case of spillages; follow the supplier's sump cleaning procedure including system cleaner type and circulation times." },
  { id: 155, group: "Metalworking Fluids", cat: "Task",  sec: "Sump Cleaning - Water-mix Fluids (MW3)",
    text: "Cleaning a large enclosed sump or underfloor tank may create a confined space risk - assess the risk and implement measures such as a permit-to-work system. Refer to Safe Work in Confined Spaces (L101) before undertaking any confined space work." },
  { id: 156, group: "Metalworking Fluids", cat: "Task",  sec: "Sump Cleaning - Water-mix Fluids (MW3)",
    text: "Follow the sump cleaning procedure: add system cleaner and circulate; empty and manually clean; clean hose connections, filters, splash screens and tramp oil separators; fill with fresh MWF at supplier's recommended concentration; test for bacteria after one week using dipslides." },
  { id: 157, group: "Metalworking Fluids", cat: "RPE",   sec: "Sump Cleaning - Water-mix Fluids (MW3)",
    text: "Provide RPE with a UK Standard APF of at least 20 (e.g. FFP3 or powered TH2) where mist is being generated, e.g. when using a high pressure water hose; use powered respirators or breathing apparatus if RPE is required for more than 1 hour continuously." },
  { id: 158, group: "Metalworking Fluids", cat: "RPE",   sec: "Sump Cleaning - Water-mix Fluids (MW3)",
    text: "If there is a risk of confined space working, select air-fed RPE; check the quality of the air supply to airline breathing apparatus at least every three months; visually check compressed airlines for signs of damage before each use." },
  { id: 159, group: "Metalworking Fluids", cat: "PPE",   sec: "Sump Cleaning - Water-mix Fluids (MW3)",
    text: "Provide thicker chemical and mechanical hazard-resistant gloves for sump cleaning (machinery switched off only); provide eye protection, overalls with forearms covered, and arrange contract laundering of contaminated workwear." },

  // MW4 - Sump cleaning: neat oils
  { id: 160, group: "Metalworking Fluids", cat: "Task",  sec: "Sump Cleaning - Neat Oils (MW4)",
    text: "Decide on sump cleaning frequency in consultation with the fluid supplier; provide equipment to remove and replace sump fluids with minimum spillage; keep absorbent material to hand in case of spillages." },
  { id: 161, group: "Metalworking Fluids", cat: "Task",  sec: "Sump Cleaning - Neat Oils (MW4)",
    text: "Follow the neat oil sump cleaning procedure: drain the oil; if contaminated, flush with compatible neat flushing oil and circulate; check flow rates and system integrity; drain and replace defective parts; refill with fresh neat oil." },
  { id: 162, group: "Metalworking Fluids", cat: "Task",  sec: "Sump Cleaning - Neat Oils (MW4)",
    text: "Assess confined space risk before cleaning large enclosed sumps or underfloor tanks; implement a permit-to-work system where required. Refer to Safe Work in Confined Spaces (L101)." },
  { id: 163, group: "Metalworking Fluids", cat: "PPE",   sec: "Sump Cleaning - Neat Oils (MW4)",
    text: "Provide thicker chemical and mechanical hazard-resistant gloves for neat oil sump cleaning (machinery switched off only); provide eye protection, overalls with forearms covered, and arrange contract laundering of contaminated workwear." },
  { id: 164, group: "Metalworking Fluids", cat: "PPE",   sec: "Sump Cleaning - Neat Oils (MW4)",
    text: "Remove clothing contaminated with neat oil immediately; provide warm water, mild skin cleansers and soft paper towels; provide pre-work and after-work emollient creams. Barrier creams are not a substitute for other controls." },
  { id: 165, group: "Metalworking Fluids", cat: "Clean", sec: "Sump Cleaning - Neat Oils (MW4)",
    text: "Deal with neat oil spills immediately using a vacuum system and absorbent materials; dispose of spilt neat oil safely - do not return it to the machine as this contaminates the system and reduces fluid life." },

  // MW5 - Managing fluid quality
  { id: 166, group: "Metalworking Fluids", cat: "Fluid", sec: "Managing Fluid Quality (MW5)",
    text: "Cover sumps to prevent contamination (e.g. from food, drinks, or other sources); minimise tramp oil leaks using mechanical skimmers, oil coalescers or vacuum systems; remove fines using centrifuges, filtration or magnetic separators." },
  { id: 167, group: "Metalworking Fluids", cat: "Fluid", sec: "Managing Fluid Quality (MW5)",
    text: "Prevent fluid stagnation in sumps and pipes by keeping fluid circulating with pumps; remove dead-ends and where practicable dead-legs; where dead-legs remain, flush at least weekly." },
  { id: 168, group: "Metalworking Fluids", cat: "Fluid", sec: "Managing Fluid Quality (MW5)",
    text: "When commissioning or modifying a MWF supply system, avoid points of low or no flow such as bottlenecks, dead-ends and dead-legs, which promote biofilm growth." },
  { id: 169, group: "Metalworking Fluids", cat: "Fluid", sec: "Managing Fluid Quality (MW5)",
    text: "Check input water quality for hardness, pH and bacteria; if using stored water, carry out weekly inspections of water storage tanks and filtration equipment." },
  { id: 170, group: "Metalworking Fluids", cat: "Fluid", sec: "Managing Fluid Quality (MW5)",
    text: "Check fluid appearance daily for unusual odour or biofilm deposits; measure fluid concentration (refractometer) and pH weekly; measure sump fluid temperature weekly; consider cooling the fluid if temperature rises significantly above workroom temperature." },
  { id: 171, group: "Metalworking Fluids", cat: "Fluid", sec: "Managing Fluid Quality (MW5)",
    text: "Check tramp oil content weekly - keep below 2%; check all strainers/filters regularly for blockages; check stored water tanks weekly for cleanliness." },
  { id: 172, group: "Metalworking Fluids", cat: "Fluid", sec: "Managing Fluid Quality (MW5)",
    text: "Take dipslides at least weekly; stir the sump before testing; use a dipslide incubator at consistent temperature; follow supplier's instructions for incubation time and temperature. Records of dipslide, concentration and pH tests can be used to justify reduced testing frequency." },
  { id: 173, group: "Metalworking Fluids", cat: "Fluid", sec: "Managing Fluid Quality (MW5)",
    text: "Dipslide results at or above 10^4 cfu/ml indicate microbial growth - first ensure all good practice fluid maintenance measures are in place before adding biocide. If bacterial growth continues, add biocide at supplier's recommended dose only, at a point of high turbulence." },
  { id: 174, group: "Metalworking Fluids", cat: "Fluid", sec: "Managing Fluid Quality (MW5)",
    text: "Dipslide results at or above 10^6 cfu/ml indicate poor control - act immediately by draining and cleaning the system. Do not add biocide as the sole response to high bacterial counts." },
  { id: 175, group: "Metalworking Fluids", cat: "Fluid", sec: "Managing Fluid Quality (MW5)",
    text: "Keep records of all fluid quality tests for at least five years; record results in a table or graph to identify trends; train personnel carrying out fluid quality checks on correct procedures, recording, result interpretation and remedial actions." },

  // ═══════════════════════════════════════════════════
  // PRINTING - HSE P Series (Lithographic printing)
  // ═══════════════════════════════════════════════════

  // ── P1: Manual film and plate development ───────────────────────────────────
  { id: 176, group: "Printing", cat: "Hazards", sec: "P1 – Manual film & plate development",
    text: "Frequent contact with solvent-based substances used in printing processes can cause dermatitis, a common problem in the industry." },
  { id: 177, group: "Printing", cat: "Hazards", sec: "P1 – Manual film & plate development",
    text: "Some fixers and plate developers can irritate the skin, leading to dermatitis." },
  { id: 178, group: "Printing", cat: "Hazards", sec: "P1 – Manual film & plate development",
    text: "Some substances used in film and plate development are very corrosive; others can cause skin allergies." },
  { id: 179, group: "Printing", cat: "Hazards", sec: "P1 – Manual film & plate development",
    text: "UV light used in plate exposure units can damage the skin and eyes." },
  { id: 180, group: "Printing", cat: "Hazards", sec: "P1 – Manual film & plate development",
    text: "Hydrofluoric acid is very toxic and can cause serious burns; damage to skin and eyes can be permanent." },
  { id: 181, group: "Printing", cat: "Hazards", sec: "P1 – Manual film & plate development",
    text: "Check safety data sheets for any workplace exposure limits applicable to substances used in film and plate development." },
  { id: 182, group: "Printing", cat: "Access", sec: "P1 – Manual film & plate development",
    text: "Restrict access to the film and plate development area to authorised and appropriately trained people only." },
  { id: 183, group: "Printing", cat: "Equipment", sec: "P1 – Manual film & plate development",
    text: "Consider whether it is reasonably practicable to use automated film and plate development (P2) in preference to manual processing." },
  { id: 184, group: "Printing", cat: "Equipment", sec: "P1 – Manual film & plate development",
    text: "Provide a good standard of general ventilation for manual film and plate development: use powered wall- or window-mounted fans to supply fresh air at greater than five air changes per hour, with a through draught." },
  { id: 185, group: "Printing", cat: "Equipment", sec: "P1 – Manual film & plate development",
    text: "Provide easy-to-clean work surfaces with lipped edges for all liquid handling in the film and plate development area." },
  { id: 186, group: "Printing", cat: "Equipment", sec: "P1 – Manual film & plate development",
    text: "Keep developing solutions in shallow trays to contain spillage." },
  { id: 187, group: "Printing", cat: "Equipment", sec: "P1 – Manual film & plate development",
    text: "Provide pumps or squeezable bottles in place of hand pouring for developing solutions." },
  { id: 188, group: "Printing", cat: "Equipment", sec: "P1 – Manual film & plate development",
    text: "Screen UV exposure units with shutters, blinds or wraparound curtains to prevent UV light exposure." },
  { id: 189, group: "Printing", cat: "SpecialCare", sec: "P1 – Manual film & plate development",
    text: "Provide deletion pens in place of jars of hydrofluoric acid deletion fluid." },
  { id: 190, group: "Printing", cat: "SpecialCare", sec: "P1 – Manual film & plate development",
    text: "Ensure first-aid procedures are adequate for hydrofluoric acid use. Stock calcium gluconate gel for hydrofluoric acid burns and keep it readily accessible." },
  { id: 191, group: "Printing", cat: "RPE", sec: "P1 – Manual film & plate development",
    text: "RPE is not normally needed for routine manual film and plate development operations." },
  { id: 192, group: "Printing", cat: "RPE", sec: "P1 – Manual film & plate development",
    text: "RPE may be needed for some cleaning and maintenance activities in the film and plate development area, e.g. cleaning up spills." },
  { id: 193, group: "Printing", cat: "PPE", sec: "P1 – Manual film & plate development",
    text: "Chemicals used in film and plate development are in hazard group S and can damage the skin and eyes, or enter the body through the skin. Check the safety data sheet to determine what PPE is required (see sheets S100 and S101)." },
  { id: 194, group: "Printing", cat: "Gloves", sec: "P1 – Manual film & plate development",
    text: "Follow any advice on the safety data sheet regarding suitable gloves for film and plate development. If no specific information is given, splash-resistant single-use nitrile gloves 0.2 mm thick are typically acceptable." },
  { id: 195, group: "Printing", cat: "OtherPPE", sec: "P1 – Manual film & plate development",
    text: "Provide eye protection for all workers involved in manual film and plate development." },
  { id: 196, group: "Printing", cat: "OtherPPE", sec: "P1 – Manual film & plate development",
    text: "Provide cotton overalls to minimise clothing contamination during film and plate development. Workers must immediately change heavily contaminated overalls and ensure they are laundered by a contract laundry before reuse — do not allow laundering at home." },
  { id: 197, group: "Printing", cat: "SkinCare", sec: "P1 – Manual film & plate development",
    text: "Provide warm water, mild skin cleansers and soft paper or fabric towels for drying in the film and plate development area. Avoid abrasive cleansers. Rinse off any hand cleansers used to remove ink. Never allow solvents to be used to clean skin." },
  { id: 198, group: "Printing", cat: "SkinCare", sec: "P1 – Manual film & plate development",
    text: "Provide pre-work creams to make it easier to wash contaminants from the skin, and after-work creams to replace skin oils. Note: barrier creams are not 'liquid gloves' and do not provide a full barrier." },
  { id: 199, group: "Printing", cat: "Maintenance", sec: "P1 – Manual film & plate development",
    text: "Keep all equipment used in manual film and plate development in effective working order, maintained as advised by the supplier or installer. Check for signs of damage to control equipment before starting work." },
  { id: 200, group: "Printing", cat: "Maintenance", sec: "P1 – Manual film & plate development",
    text: "Have equipment for film and plate development thoroughly examined and tested against its performance standard at suitable intervals. Keep records of all examinations and tests for at least five years." },
  { id: 201, group: "Printing", cat: "Housekeeping", sec: "P1 – Manual film & plate development",
    text: "Clean film and plate development equipment and the work area daily; clean the wider workroom at least once a week. Store containers safely, dispose of empty containers properly, and replace lids immediately after use." },
  { id: 202, group: "Printing", cat: "Housekeeping", sec: "P1 – Manual film & plate development",
    text: "Deal with any spills immediately: contain or absorb liquids with granules or mats. For larger spills workers may need RPE, an impervious apron, and 0.4 mm thick nitrile gloves. Dispose of used gloves, granules, mats and cloths as hazardous waste." },
  { id: 203, group: "Printing", cat: "Health", sec: "P1 – Manual film & plate development",
    text: "Provide health surveillance for dermatitis where there is a reasonable likelihood of it occurring in the film and plate development area (see sheet G403)." },
  { id: 204, group: "Printing", cat: "Training", sec: "P1 – Manual film & plate development",
    text: "Train workers on the harmful nature of substances used in film and plate development, the signs of dermatitis, how to use controls correctly, how to check controls are working, and what to do if something goes wrong. Involve managers and supervisors. Maintain training records." },

  // ── P2: Automated film and plate development ──────────────────────────────
  { id: 205, group: "Printing", cat: "Equipment", sec: "P2 – Automated film & plate development",
    text: "Use automatic processors with closed panels and closed liquid transfers (solutions pumped from reservoirs to waste containers) for film and plate development." },
  { id: 206, group: "Printing", cat: "Equipment", sec: "P2 – Automated film & plate development",
    text: "Extract vapours from the automatic processor when making larger plates or during longer plate-making runs. Wire the extraction (LEV) directly to the processor unit." },
  { id: 207, group: "Printing", cat: "Equipment", sec: "P2 – Automated film & plate development",
    text: "Airflow into openings on the automatic plate processor must be sufficient to effectively control airborne contaminants; this will depend on the design and size of openings (see HSG258)." },
  { id: 208, group: "Printing", cat: "Equipment", sec: "P2 – Automated film & plate development",
    text: "Fit a manometer, pressure gauge or tell-tale to the automatic processor extraction to confirm that ventilation is working." },
  { id: 209, group: "Printing", cat: "Equipment", sec: "P2 – Automated film & plate development",
    text: "Interlock UV lamps on automatic processors with the unit's fixed covers to prevent unintended UV exposure." },
  { id: 210, group: "Printing", cat: "Gloves", sec: "P2 – Automated film & plate development",
    text: "Gloves should not be needed for routine automated film and plate development operations, but may be required for cleaning, maintenance, or spill response activities." },

  // ── P3: Ink mixing and cleaning up ───────────────────────────────────────
  { id: 211, group: "Printing", cat: "Hazards", sec: "P3 – Ink mixing & cleaning up",
    text: "Some solvent-based substances used in ink mixing can be absorbed through the skin and cause harm elsewhere in the body." },
  { id: 212, group: "Printing", cat: "Hazards", sec: "P3 – Ink mixing & cleaning up",
    text: "Some solvent-based substances used in ink mixing can be harmful if high concentrations of vapour are breathed in, causing dizziness, drowsiness and other effects on the central nervous system." },
  { id: 213, group: "Printing", cat: "Equipment", sec: "P3 – Ink mixing & cleaning up",
    text: "Use UV-curable inks and coatings that conform to the Acrylate Preference Criteria." },
  { id: 214, group: "Printing", cat: "Equipment", sec: "P3 – Ink mixing & cleaning up",
    text: "Where reasonably practicable, avoid hand-pouring inks and reducers by providing pumped transfer systems or dispensing aids." },
  { id: 215, group: "Printing", cat: "Equipment", sec: "P3 – Ink mixing & cleaning up",
    text: "Store ink containers securely closed in a safe place. Handle containers with care, replace caps promptly, and replace covers on ink ducts immediately after use." },
  { id: 216, group: "Printing", cat: "Gloves", sec: "P3 – Ink mixing & cleaning up",
    text: "Follow any advice on the safety data sheet regarding suitable gloves for ink mixing. If no specific information is given, nitrile gloves 0.4 mm thick are typically acceptable. Ensure workers wear them." },
  { id: 217, group: "Printing", cat: "Maintenance", sec: "P3 – Ink mixing & cleaning up",
    text: "Check transfer hoses and connectors regularly for leaks as part of maintenance of ink mixing and transfer equipment." },

  // ── P4: Printing with conventional inks ──────────────────────────────────
  { id: 218, group: "Printing", cat: "Equipment", sec: "P4 – Printing with conventional inks",
    text: "Where reasonably practicable, transfer ink to the press via fixed pipework, or use proprietary mixing systems and automatic cartridges to dispense inks to ducts, to minimise manual handling." },
  { id: 219, group: "Printing", cat: "Gloves", sec: "P4 – Printing with conventional inks",
    text: "Gloves should not be needed for routine litho printing with conventional inks, but may be required for cleaning, maintenance, or spill response activities." },
  { id: 220, group: "Printing", cat: "OtherPPE", sec: "P4 – Printing with conventional inks",
    text: "Provide cotton overalls to minimise clothing contamination during conventional litho printing. Workers must immediately change heavily contaminated overalls and arrange laundering via a contract laundry — do not allow laundering at home." },

  // ── P5: Manual cleaning of presses (conventional inks) ───────────────────
  { id: 221, group: "Printing", cat: "Equipment", sec: "P5 – Manual press cleaning (conventional inks)",
    text: "Where reasonably practicable, introduce automatic press cleaning systems (P6) to reduce the risk of skin contact with cleaning solvents." },
  { id: 222, group: "Printing", cat: "Equipment", sec: "P5 – Manual press cleaning (conventional inks)",
    text: "Consider whether cleaning products with lower volatility or a higher flashpoint can be used for manual press cleaning." },
  { id: 223, group: "Printing", cat: "Equipment", sec: "P5 – Manual press cleaning (conventional inks)",
    text: "Use a wiping tool in place of rags or cloths where possible, and minimise manual wiping during press cleaning." },
  { id: 224, group: "Printing", cat: "Equipment", sec: "P5 – Manual press cleaning (conventional inks)",
    text: "If the press is fitted with extraction (LEV), turn it on during cleaning. The press should be stationary." },
  { id: 225, group: "Printing", cat: "Equipment", sec: "P5 – Manual press cleaning (conventional inks)",
    text: "Provide a good through draught using a fan or air mover for work in restricted or confined areas during press cleaning, e.g. when removing ink from cylinders or working in dead spaces between machines." },
  { id: 226, group: "Printing", cat: "Gloves", sec: "P5 – Manual press cleaning (conventional inks)",
    text: "Use nitrile gloves 0.4 mm thick for manual press cleaning. Ensure workers wear them and discard damaged gloves immediately." },
  { id: 227, group: "Printing", cat: "OtherPPE", sec: "P5 – Manual press cleaning (conventional inks)",
    text: "Provide anti-static footwear for workers undertaking manual press cleaning with flammable solvents." },
  { id: 228, group: "Printing", cat: "LEV", sec: "P5 – Manual press cleaning (conventional inks)",
    text: "LEV systems on presses require statutory thorough examination and testing (TExT) by a competent ventilation engineer at least once every 14 months (see HSG258). Carry out all actions arising from the TExT and keep records for at least five years." },
  { id: 229, group: "Printing", cat: "LEV", sec: "P5 – Manual press cleaning (conventional inks)",
    text: "Maintain a user manual or log book for press LEV systems, setting out the frequency of checking, maintenance and parts replacement. Where no manual exists, seek guidance from a competent person to determine the performance standard needed." },
  { id: 230, group: "Printing", cat: "Housekeeping", sec: "P5 – Manual press cleaning (conventional inks)",
    text: "Store contaminated cloths, wipes and gloves from press cleaning in fire-resistant, closed metal containers." },
  { id: 231, group: "Printing", cat: "Housekeeping", sec: "P5 – Manual press cleaning (conventional inks)",
    text: "Minimise the amount of flammable cleaning liquids in use at any one time. Use a self-sealing container or proprietary dispenser for cleaning solvents." },

  // ── P6: Automated cleaning of presses (conventional inks) ────────────────
  { id: 232, group: "Printing", cat: "Equipment", sec: "P6 – Automated press cleaning (conventional inks)",
    text: "Use closed pump transfer for cleaning solvents in automated press cleaning systems." },
  { id: 233, group: "Printing", cat: "Equipment", sec: "P6 – Automated press cleaning (conventional inks)",
    text: "Check that cleaning solvents used in the automated blanket wash system are compatible with any plastic or rubber components, e.g. flexible hoses and day tanks." },
  { id: 234, group: "Printing", cat: "Equipment", sec: "P6 – Automated press cleaning (conventional inks)",
    text: "Ensure the quantity of cleaning solvent applied by the automatic blanket wash system is metered to the minimum necessary and is only altered by authorised personnel." },
  { id: 235, group: "Printing", cat: "OtherPPE", sec: "P6 – Automated press cleaning (conventional inks)",
    text: "Note that gloves increase the risk of entanglement with moving rollers and cylinders. Workers should be reminded of this risk when wearing gloves near running machinery." },

  // ── P7: Printing with UV-curable inks and coatings ───────────────────────
  { id: 236, group: "Printing", cat: "Hazards", sec: "P7 – Printing with UV-curable inks",
    text: "Acrylate inks used in UV-curable printing may cause skin allergies." },
  { id: 237, group: "Printing", cat: "Hazards", sec: "P7 – Printing with UV-curable inks",
    text: "Ozone generated by UV ink-curing lamps can irritate the airways." },
  { id: 238, group: "Printing", cat: "Equipment", sec: "P7 – Printing with UV-curable inks",
    text: "Set up the press to minimise ink misting when printing with UV-curable inks. Use LEV to remove mist or shroud the rollers to trap it; consider water-cooling on cylinders." },
  { id: 239, group: "Printing", cat: "Equipment", sec: "P7 – Printing with UV-curable inks",
    text: "Screen UV curing units with fixed or interlocked covers to prevent UV light leakage. Use extraction to remove ozone produced by the UV lamps." },
  { id: 240, group: "Printing", cat: "Equipment", sec: "P7 – Printing with UV-curable inks",
    text: "Consider using water-cooled UV lamps, which generate less ozone than air-cooled equivalents." },
  { id: 241, group: "Printing", cat: "Equipment", sec: "P7 – Printing with UV-curable inks",
    text: "Wire ozone extraction directly to the UV lamp power supply so it operates whenever the lamps are on." },
  { id: 242, group: "Printing", cat: "Maintenance", sec: "P7 – Printing with UV-curable inks",
    text: "Check airflow indicators for the press and UV unit extraction at least once a week to confirm they are working correctly." },
  { id: 243, group: "Printing", cat: "Maintenance", sec: "P7 – Printing with UV-curable inks",
    text: "Ensure screens on UV curing units are secure and all interlocks are in working order before and during production." },
  { id: 244, group: "Printing", cat: "Training", sec: "P7 – Printing with UV-curable inks",
    text: "Train workers operating UV-curable ink presses on how the LEV system works, how to use it effectively, and how to check it is functioning — in addition to general hazardous substance and dermatitis training." },

  // ── P8: Manual cleaning of presses (UV-curable inks) ─────────────────────
  { id: 245, group: "Printing", cat: "Equipment", sec: "P8 – Manual press cleaning (UV-curable inks)",
    text: "Minimise the use of highly volatile cleaning solvents, e.g. those containing methyl ethyl ketone. If using more than 0.5 litres per day or for more than 30 minutes, vapour extraction is required." },
  { id: 246, group: "Printing", cat: "OtherPPE", sec: "P8 – Manual press cleaning (UV-curable inks)",
    text: "Provide an impervious apron for workers manually cleaning presses with UV-curable inks and coatings." },

  // ── P9: Automated cleaning of presses (UV-curable inks) ──────────────────
  { id: 247, group: "Printing", cat: "Equipment", sec: "P9 – Automated press cleaning (UV-curable inks)",
    text: "Ensure the quantity of cleaning chemicals applied by the automatic blanket wash system on UV-curable ink presses is metered to the minimum necessary and is only altered by authorised personnel." },

  // ── P10: Printing with cold-set inks ─────────────────────────────────────
  { id: 248, group: "Printing", cat: "Hazards", sec: "P10 – Printing with cold-set inks",
    text: "Some solvent-based substances used in cold-set ink printing can be absorbed through the skin and cause harm elsewhere in the body." },
  { id: 249, group: "Printing", cat: "Hazards", sec: "P10 – Printing with cold-set inks",
    text: "Some solvent-based substances used in cold-set ink printing can be harmful if high concentrations of vapour are breathed in, causing dizziness, drowsiness and other effects on the central nervous system. Check safety data sheets for workplace exposure limits." },
  { id: 250, group: "Printing", cat: "Equipment", sec: "P10 – Printing with cold-set inks",
    text: "Where reasonably practicable, transfer cold-set ink to the press via fixed pipework, or use proprietary mixing systems and automatic cartridges to dispense inks to ducts." },
  { id: 251, group: "Printing", cat: "Gloves", sec: "P10 – Printing with cold-set inks",
    text: "Gloves should not be needed for routine litho printing with cold-set inks, but may be required for cleaning, maintenance, or spill response activities." },
];
